    34→#ifdef EN_PERF
    35→static volatile float g_acc;
    36→
    37→static void emit(float x)
    38→{
    39→    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    40→    g_acc += asinf(vx);
    41→}
    42→
    43→static void emit_u(uint32_t bits)
    44→{
    45→    emit(u2f(bits));
    46→}
    47→#else
    48→static void emit(float x)
    49→{
    50→    float r = asinf(x);
    51→    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
    52→}
    53→
    54→static void emit_u(uint32_t bits)
    55→{
    56→    emit(u2f(bits));
    57→}
    58→#endif
