    60→/* ------------------------------------------------------------------ */
    61→/* 100 representative test points for asinf                           */
    62→/* Domain: [-1, 1]; inputs outside return NaN (domain error)          */
    63→/* ------------------------------------------------------------------ */
    64→
    65→static void test_representative_100(void)
    66→{
    67→    /* --- Section 1: Special IEEE 754 values (7) --- */
    68→    emit(0.0f);
    69→    emit(-0.0f);
    70→    emit_u(0x7fc00000u);  /* qNaN */
    71→    emit_u(0x7f800001u);  /* sNaN */
    72→    emit_u(0xffc00000u);  /* -qNaN */
    73→    emit_u(0x7f800000u);  /* +Inf (out of domain) */
    74→    emit_u(0xff800000u);  /* -Inf (out of domain) */
    75→
    76→    /* --- Section 2: Subnormal (denormal) values (6) --- */
    77→    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    78→    emit_u(0x80000001u);  /* min negative subnormal: -2^-149 */
    79→    emit_u(0x00400000u);  /* mid positive subnormal */
    80→    emit_u(0x80400000u);  /* mid negative subnormal */
    81→    emit_u(0x007fffffu);  /* max positive subnormal: just below FLT_MIN */
    82→    emit_u(0x807fffffu);  /* max negative subnormal */
    83→
    84→    /* --- Section 3: Normal boundary values (6) --- */
    85→    emit(FLT_MIN);                /* 2^-126, smallest normal positive */
    86→    emit(-FLT_MIN);               /* smallest normal negative */
    87→    emit_u(0x00800001u);          /* one ULP above FLT_MIN */
    88→    emit_u(0x7f7fffffu);          /* FLT_MAX: out of domain, returns NaN */
    89→    emit_u(0xff7fffffu);          /* -FLT_MAX: out of domain, returns NaN */
    90→    emit_u(0x7f7ffffeu);          /* one ULP below FLT_MAX, also out of domain */
    91→
    92→    /* --- Section 4: Near +1.0 and -1.0 ULP neighbors (8) --- */
    93→    emit_u(0x3f7ffffeu);  /* two ULPs below 1.0: ~0.9999998 */
    94→    emit_u(0x3f7fffffu);  /* one ULP below 1.0: ~0.9999999 */
    95→    emit_u(0x3f800000u);  /* exactly 1.0: asinf(1.0) = pi/2 */
    96→    emit_u(0x3f800001u);  /* one ULP above 1.0: out of domain */
    97→    emit_u(0xbf800001u);  /* one ULP away from zero past -1.0: out of domain */
    98→    emit_u(0xbf800000u);  /* exactly -1.0: asinf(-1.0) = -pi/2 */
    99→    emit_u(0xbf7fffffu);  /* one ULP toward zero from -1.0: ~-0.9999999 */
   100→    emit_u(0xbf7ffffeu);  /* two ULPs toward zero from -1.0: ~-0.9999998 */
   101→
   102→    /* --- Section 5: Exponent switching near 0.5 boundary (6) --- */
   103→    /* asinf switches polynomial branch at |x| = 0.5 */
   104→    emit_u(0x3effffffu);  /* one ULP below 0.5 */
   105→    emit_u(0x3f000000u);  /* exactly 0.5: asinf(0.5) = pi/6 */
   106→    emit_u(0x3f000001u);  /* one ULP above 0.5 */
   107→    emit_u(0xbeffffffu);  /* one ULP toward zero from -0.5 */
   108→    emit_u(0xbf000000u);  /* exactly -0.5: asinf(-0.5) = -pi/6 */
   109→    emit_u(0xbf000001u);  /* one ULP away from zero past -0.5 */
   110→
   111→    /* --- Section 6: Known mathematical values (14) --- */
   112→    /* asinf(0.5)   = pi/6  ~ 0.5236 rad (30 deg) */
   113→    /* asinf(sqrt2/2) = pi/4 ~ 0.7854 rad (45 deg) */
   114→    /* asinf(sqrt3/2) = pi/3 ~ 1.0472 rad (60 deg) */
   115→    emit(0.5f);
   116→    emit(-0.5f);
   117→    emit_u(0x3f3504f3u);   /* sqrt(2)/2 ~ 0.70710678: asinf = pi/4 */
   118→    emit_u(0xbf3504f3u);   /* -sqrt(2)/2 */
   119→    emit_u(0x3f6ed9f0u);   /* sqrt(3)/2 ~ 0.86602540: asinf = pi/3 */
   120→    emit_u(0xbf6ed9f0u);   /* -sqrt(3)/2 */
   121→    emit(0.1f);
   122→    emit(-0.1f);
   123→    emit(0.25f);
   124→    emit(-0.25f);
   125→    emit(0.75f);
   126→    emit(-0.75f);
   127→    emit(0.9f);
   128→    emit(-0.9f);
   129→
   130→    /* --- Section 7: Tiny-argument fast-path thresholds (8) --- */
   131→    /* For |x| << 1, asinf(x) ~ x; test near implementation thresholds */
   132→    emit_u(0x39800000u);   /* 2^-12 ~ 2.44e-4 */
   133→    emit_u(0xb9800000u);   /* -2^-12 */
   134→    emit_u(0x33800000u);   /* 2^-24 ~ 5.96e-8, near float epsilon */
   135→    emit_u(0xb3800000u);   /* -2^-24 */
   136→    emit(1.0e-10f);
   137→    emit(-1.0e-10f);
   138→    emit(1.0e-20f);
   139→    emit(-1.0e-20f);
   140→
   141→    /* --- Section 8: Dense coverage near polynomial branch boundary (9) --- */
   142→    /* Several ULPs around 0.5 and -0.5 to stress the branch transition */
   143→    emit_u(0x3efffffeu);   /* two ULPs below 0.5 */
   144→    emit_u(0x3f000002u);   /* two ULPs above 0.5 */
   145→    emit_u(0x3f000008u);   /* eight ULPs above 0.5 */
   146→    emit_u(0xbefffffeu);   /* two ULPs toward zero from -0.5 */
   147→    emit_u(0xbf000002u);   /* two ULPs away from zero past -0.5 */
   148→    emit_u(0xbf000008u);   /* eight ULPs past -0.5 */
   149→    /* Also stress near 1/sqrt(2) = 0.707..., another common branch point */
   150→    emit_u(0x3f3504f2u);   /* one ULP below sqrt(2)/2 */
   151→    emit_u(0x3f3504f4u);   /* one ULP above sqrt(2)/2 */
   152→    emit_u(0x3f3504f0u);   /* several ULPs below sqrt(2)/2 */
   153→
   154→    /* --- Section 9: Evenly spaced coverage across domain (14) --- */
   155→    emit(-0.99f);
   156→    emit(-0.95f);
   157→    emit(-0.8f);
   158→    emit(-0.6f);
   159→    emit(-0.4f);
   160→    emit(-0.3f);
   161→    emit(-0.2f);
   162→    emit(-0.05f);
   163→    emit(0.05f);
   164→    emit(0.2f);
   165→    emit(0.3f);
   166→    emit(0.4f);
   167→    emit(0.6f);
   168→    emit(0.8f);
   169→
   170→    /* --- Section 10: Out-of-domain and hard boundary cases (22) --- */
   171→    /* All inputs with |x| > 1 must return NaN */
   172→    emit(1.5f);
   173→    emit(-1.5f);
   174→    emit(2.0f);
   175→    emit(-2.0f);
   176→    emit(10.0f);
   177→    emit(-10.0f);
   178→    emit(100.0f);
   179→    emit(-100.0f);
   180→    emit_u(0x3f800002u);   /* two ULPs above 1.0: out of domain */
   181→    emit_u(0xbf800002u);   /* two ULPs below -1.0: out of domain */
   182→    /* Near-boundary: just inside ±1 at increasing distances */
   183→    emit(0.999f);
   184→    emit(-0.999f);
   185→    emit(0.9999f);
   186→    emit(-0.9999f);
   187→    emit(0.99999f);
   188→    emit(-0.99999f);
   189→    emit(0.999999f);
   190→    emit(-0.999999f);
   191→    /* Exact domain edge bit patterns */
   192→    emit_u(0x3f7ffff0u);   /* 16 ULPs below 1.0 */
   193→    emit_u(0x3f7fffe0u);   /* 32 ULPs below 1.0 */
   194→    emit_u(0xbf7ffff0u);   /* 16 ULPs toward zero from -1.0 */
   195→    emit_u(0xbf7fffe0u);   /* 32 ULPs toward zero from -1.0 */
   196→}
   197→
   198→/* --- Dense sweep and exhaustive small-range tests (accuracy path only) --- */
   199→
   200→#ifndef EN_PERF
   201→/* Sweep [-1, 1] in 200 steps */
   202→static void test_sweep(void)
   203→{
   204→    int nsteps = 200;
   205→    for (int i = 0; i <= nsteps; i++)
   206→        emit(-1.0f + 2.0f * (float)i / (float)nsteps);
   207→}
   208→
   209→/* Exhaustive [-1, 1] every 65536 ULP */
   210→static void test_exhaustive_small(void)
   211→{
   212→    uint32_t start = 0xbf800000u; /* -1.0 */
   213→    uint32_t end = 0x3f800000u;   /* 1.0 */
   214→    for (uint32_t b = start; b <= end; b += 65536) {
   215→        if (b >= start && b <= end)
   216→            emit_u(b);
   217→    }
   218→}
   219→#endif
   220→
   221→/* ------------------------------------------------------------------ */
   222→
   223→int main(void)
   224→{
   225→#ifdef EN_PERF
